class Solution:
    def numberOfStableArrays(self, zero: int, one: int, limit: int) -> int:
        # Simple O(z*o*L) DP - independent formulation from the optimal prefix-sum version
        MOD = 10**9 + 7
        f0 = [[0]*(one+1) for _ in range(zero+1)]
        f1 = [[0]*(one+1) for _ in range(zero+1)]
        for r in range(1, min(zero, limit)+1):
            f0[r][0] = 1
        for r in range(1, min(one, limit)+1):
            f1[0][r] = 1
        for i in range(zero+1):
            for j in range(one+1):
                if i == 0 or j == 0:
                    continue
                f0[i][j] = sum(f1[i-r][j] for r in range(1, min(i,limit)+1)) % MOD
                f1[i][j] = sum(f0[i][j-r] for r in range(1, min(j,limit)+1)) % MOD
        return (f0[zero][one] + f1[zero][one]) % MOD

