        f0 = [[0]*(one+1) for _ in range(zero+1)]
        f1 = [[0]*(one+1) for _ in range(zero+1)]
        for r in range(1, min(zero, limit)+1):
            f0[r][0] = 1
        for r in range(1, min(one, limit)+1):
            f1[0][r] = 1
        p1 = [[0]*(one+1) for _ in range(zero+1)]
        for j in range(one+1):
            p1[0][j] = f1[0][j]
        for i in range(1, zero+1):
            p0_i = [0]*(one+2)
            p0_i[1] = f0[i][0]
            for j in range(1, one+1):
                lo = i - limit - 1
                f0[i][j] = (p1[i-1][j] - (p1[lo][j] if lo >= 0 else 0) + MOD) % MOD
                lo2 = max(0, j - limit)
                f1[i][j] = (p0_i[j] - p0_i[lo2] + MOD) % MOD
                p0_i[j+1] = (p0_i[j] + f0[i][j]) % MOD
            for j in range(one+1):
                p1[i][j] = (p1[i-1][j] + f1[i][j]) % MOD
        return (f0[zero][one] + f1[zero][one]) % MOD

