var numberOfStableArrays = function(zero, one, limit) {
    const MOD = 1000000007n;
    const f0 = Array.from({length: zero+1}, () => new Array(one+1).fill(0n));
    const f1 = Array.from({length: zero+1}, () => new Array(one+1).fill(0n));
    for (let r = 1; r <= Math.min(zero, limit); r++) f0[r][0] = 1n;
    for (let r = 1; r <= Math.min(one, limit); r++) f1[0][r] = 1n;
    const p1 = Array.from({length: zero+1}, () => new Array(one+1).fill(0n));
    for (let j = 0; j <= one; j++) p1[0][j] = f1[0][j];
    for (let i = 1; i <= zero; i++) {
        const p0i = new Array(one+2).fill(0n);
        p0i[1] = f0[i][0];
        for (let j = 1; j <= one; j++) {
            const lo = i - limit - 1;
            f0[i][j] = (p1[i-1][j] - (lo >= 0 ? p1[lo][j] : 0n) + MOD) % MOD;
            const lo2 = Math.max(0, j - limit);
            f1[i][j] = (p0i[j] - p0i[lo2] + MOD) % MOD;
            p0i[j+1] = (p0i[j] + f0[i][j]) % MOD;
        }
        for (let j = 0; j <= one; j++) p1[i][j] = (p1[i-1][j] + f1[i][j]) % MOD;
    }
    return Number((f0[zero][one] + f1[zero][one]) % MOD);
};
